<?php
declare(strict_types=1);
namespace App\Factory\Models;
use App\Factory\Events\FactoryExecutionFailed; use App\Factory\Events\FactoryExecutionFinished; use App\Factory\Events\FactoryExecutionStarted; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo; use Illuminate\Database\Eloquent\Relations\HasMany; use Illuminate\Database\Eloquent\SoftDeletes;
class FactoryExecution extends Model { use SoftDeletes; protected $table='factory_executions'; protected $fillable=['uuid','factory_project_id','factory_capability_id','factory_blueprint_id','name','status','attempt','input','output','context','error_message','started_at','finished_at','duration_ms','created_by','updated_by']; protected $casts=['attempt'=>'integer','input'=>'array','output'=>'array','context'=>'array','started_at'=>'datetime','finished_at'=>'datetime','duration_ms'=>'integer']; public function project(): BelongsTo { return $this->belongsTo(FactoryProject::class,'factory_project_id'); } public function capability(): BelongsTo { return $this->belongsTo(FactoryCapability::class,'factory_capability_id'); } public function blueprint(): BelongsTo { return $this->belongsTo(FactoryBlueprint::class,'factory_blueprint_id'); } public function logs(): HasMany { return $this->hasMany(FactoryExecutionLog::class,'factory_execution_id'); } public function markAsRunning(): void { $this->forceFill(['status'=>'running','started_at'=>now(),'finished_at'=>null,'duration_ms'=>null,'error_message'=>null])->save(); event(new FactoryExecutionStarted($this->refresh())); } public function markAsFinished(array $output=[]): void { $finishedAt=now(); $this->forceFill(['status'=>'finished','output'=>$output,'finished_at'=>$finishedAt,'duration_ms'=>$this->started_at ? (int) $this->started_at->diffInMilliseconds($finishedAt) : null,'error_message'=>null])->save(); event(new FactoryExecutionFinished($this->refresh())); } public function markAsFailed(string $message,array $context=[]): void { $finishedAt=now(); $this->forceFill(['status'=>'failed','context'=>array_merge($this->context ?? [], $context),'error_message'=>$message,'finished_at'=>$finishedAt,'duration_ms'=>$this->started_at ? (int) $this->started_at->diffInMilliseconds($finishedAt) : null])->save(); event(new FactoryExecutionFailed($this->refresh(), $message)); } }
